198	
199		for (const key in masked) {
200			if (Object.prototype.hasOwnProperty.call(masked, key)) {
201				const lowerKey = key.toLowerCase();
202	
203				if (
204					sensitiveKeys.some((sensitiveKey) =>
205						lowerKey.includes(sensitiveKey.toLowerCase()),
206					)
207				) {
208					masked[key] = '***MASKED***';
209				} else if (typeof masked[key] === 'object' && masked[key] !== null) {
210					masked[key] = maskSensitiveData(masked[key], sensitiveKeys);
211				}
212			}
